  // === DRILL-DOWN PANEL (click-to-expand provenance system) ===
  // "Read! In the name of your Lord who created" â€” 96:1

  let _drillDownEscHandler = null;
  function showDrillDownPanel(title, bodyHtml) {
    const panel = document.getElementById('drillDownPanel');
    const titleEl = document.getElementById('drillDownTitle');
    const bodyEl = document.getElementById('drillDownBody');
    if (!panel || !titleEl || !bodyEl) return;
    titleEl.textContent = title;
    bodyEl.innerHTML = bodyHtml;
    panel.style.display = 'block';
    panel.scrollTop = 0;
    panel.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
    // Focus the close button for keyboard users
    const closeBtn = panel.querySelector('button[aria-label="Close drill-down"]');
    if (closeBtn) closeBtn.focus();
    // Escape key closes the panel (removes on close, prevents stacking)
    if (_drillDownEscHandler) document.removeEventListener('keydown', _drillDownEscHandler);
    _drillDownEscHandler = function(e) {
      if (e.key === 'Escape') {
        panel.style.display = 'none';
        document.removeEventListener('keydown', _drillDownEscHandler);
        _drillDownEscHandler = null;
      }
    };
    document.addEventListener('keydown', _drillDownEscHandler);
  }

