      var ciVal = (s.lower_ci != null && s.upper_ci != null) ? '[' + s.lower_ci.toFixed(2) + ', ' + s.upper_ci.toFixed(2) + ']' : 'N/A';
      var titleShort = (s.title || '').length > 80 ? s.title.substring(0, 77) + '...' : (s.title || '');
      var rowBg = i % 2 === 0 ? '' : 'background:var(--bg-alt,#f8fafc);';
      html += '<tr style="' + rowBg + '">';
