  // Drill-down for Ayat Universe node (non-Al-Burhan): shows trials in intervention cluster
  function drillDownAyatNode(node) {
    if (!node || !universeTrialsCache) return;
    // Filter trials matching this node's subcategory and label
    var matchTrials = universeTrialsCache.filter(function(t) {
      if (t.subcategory !== node.subcatId) return false;
      var label = (node.label || '').toLowerCase();
      var ivNames = getTrialInterventionNames(t, { excludeComparators: true, maxItems: 6 })
        .map(function(ivName) { return ivName.toLowerCase(); });
      return ivNames.some(function(n) { return n.includes(label) || label.includes(n); });
    });
    // Fallback: all trials in subcategory
    if (matchTrials.length === 0) {
      matchTrials = universeTrialsCache.filter(function(t) { return t.subcategory === node.subcatId; });
    }

    var aactN = matchTrials.filter(function(t) { return t.source === 'aact'; }).length;
    var ctgovN = matchTrials.length - aactN;
    var html = '<div style="margin-bottom:8px;font-size:0.85rem">';
    html += '<strong>' + escapeHtml(node.subcatLabel) + '</strong> | ' + matchTrials.length + ' matching trials';
    if (aactN > 0) html += ' (' + aactN + ' AACT + ' + ctgovN + ' CT.gov)';
    html += ' | ' + node.trialCount + ' in cluster | Enrollment: ' + (node.enrollment > 1000 ? Math.round(node.enrollment/1000) + 'K' : node.enrollment);
    html += '</div>';

    // Hukm verdict banner (if computed for this node)
    var hukm = _hukmVerdicts.get(node.id);
    if (hukm) {
      var icon = HUKM_ICONS[hukm.verdict] || HUKM_ICONS.INCONCLUSIVE;
      html += '<div style="margin-bottom:10px;padding:8px 12px;border-radius:6px;background:' + icon.color + '18;border-left:4px solid ' + icon.color + '">';
      html += '<div style="font-weight:700;color:' + icon.color + ';font-size:0.85rem">Hukm: ' + escapeHtml(hukm.verdict) + '</div>';
      html += '<div style="font-size:0.78rem;color:var(--text-muted);margin-top:2px">' + escapeHtml(hukm.reasoning) + '</div>';
      html += '<div style="font-size:0.72rem;color:var(--text-muted);margin-top:4px">';
      html += 'Volume: ' + escapeHtml(hukm.signals.trialVolume) + ' | Phase: ' + escapeHtml(hukm.signals.phaseMaturity);
      html += ' | Activity: ' + escapeHtml(hukm.signals.recentActivity) + ' | Enrollment: ' + escapeHtml(hukm.signals.enrollmentMass);
      if (hukm.signals.outcomeConsistency !== 'unknown') html += ' | Consistency: ' + escapeHtml(hukm.signals.outcomeConsistency);
      html += '</div></div>';
    }

    html += '<div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:0.82rem">';
    html += '<thead><tr style="background:var(--bg-alt,#f8fafc);text-align:left">';
    html += '<th style="padding:6px 8px;border-bottom:2px solid var(--border)">NCT ID</th>';
    html += '<th style="padding:6px 8px;border-bottom:2px solid var(--border)">Title</th>';
    html += '<th style="padding:6px 8px;border-bottom:2px solid var(--border)">Interventions</th>';
    html += '<th style="padding:6px 8px;border-bottom:2px solid var(--border)">Outcomes</th>';
    html += '<th style="padding:6px 8px;border-bottom:2px solid var(--border);text-align:right">N</th>';
    html += '<th style="padding:6px 8px;border-bottom:2px solid var(--border)">Phase</th>';
    html += '<th style="padding:6px 8px;border-bottom:2px solid var(--border)">Year</th>';
    html += '<th style="padding:6px 8px;border-bottom:2px solid var(--border)">Source</th>';
    html += '</tr></thead><tbody>';

    var displayTrials = matchTrials.slice(0, 50);
    for (var i = 0; i < displayTrials.length; i++) {
      var t = displayTrials[i];
      var nctLink = t.nctId
        ? '<a href="https://clinicaltrials.gov/study/' + escapeHtml(t.nctId) + '" target="_blank" rel="noopener" style="color:var(--primary);font-family:monospace;font-size:0.78rem">' + escapeHtml(t.nctId) + '</a>'
        : 'N/A';
      var titleShort = (t.title || '').length > 60 ? t.title.substring(0, 57) + '...' : (t.title || '');
      // AACT enrichment: conditions and arm count in title tooltip
      var titleTooltip = t.title || '';
      if (t.source === 'aact') {
        if (t.conditions && t.conditions.length > 0) titleTooltip += '\nConditions: ' + t.conditions.join(', ');
        if (t.arms && t.arms.length > 0) titleTooltip += '\nArms: ' + t.arms.length;
      }
      var ivs = getTrialInterventionNames(t, {
        excludeComparators: true,
        maxItems: 6,
        fallbackLabel: 'Intervention not specified'
      }).join(', ');
      if (ivs.length > 50) ivs = ivs.substring(0, 47) + '...';
      var ocs = (t.primaryOutcomes || []).join(', ');
      if (ocs.length > 50) ocs = ocs.substring(0, 47) + '...';
      var rowBg = i % 2 === 0 ? '' : 'background:var(--bg-alt,#f8fafc);';
      html += '<tr style="' + rowBg + '">';
      html += '<td style="padding:5px 8px;border-bottom:1px solid var(--border);white-space:nowrap">' + nctLink + '</td>';
      html += '<td style="padding:5px 8px;border-bottom:1px solid var(--border)" title="' + escapeHtml(titleTooltip) + '">' + escapeHtml(titleShort) + '</td>';
      html += '<td style="padding:5px 8px;border-bottom:1px solid var(--border);font-size:0.78rem" title="' + escapeHtml(ivs) + '">' + escapeHtml(ivs) + '</td>';
      html += '<td style="padding:5px 8px;border-bottom:1px solid var(--border);font-size:0.78rem" title="' + escapeHtml(ocs) + '">' + escapeHtml(ocs) + '</td>';
      html += '<td style="padding:5px 8px;border-bottom:1px solid var(--border);text-align:right">' + escapeHtml(String(t.enrollment || '?')) + '</td>';
      html += '<td style="padding:5px 8px;border-bottom:1px solid var(--border)">' + escapeHtml(String(t.phase || '?')) + '</td>';
      html += '<td style="padding:5px 8px;border-bottom:1px solid var(--border)">' + escapeHtml(String(t.startYear || '?')) + '</td>';
      var srcBadge = t.source === 'aact'
        ? '<span style="background:#22d3ee;color:#0e1b27;padding:1px 5px;border-radius:3px;font-size:0.7rem;font-weight:600">AACT</span>'
        : '<span style="background:#94a3b8;color:#fff;padding:1px 5px;border-radius:3px;font-size:0.7rem">CT.gov</span>';
      html += '<td style="padding:5px 8px;border-bottom:1px solid var(--border)">' + srcBadge + '</td>';
      html += '</tr>';
    }
    html += '</tbody></table></div>';
    if (matchTrials.length > 50) {
      html += '<div style="margin-top:6px;font-size:0.8rem;color:var(--text-muted)">Showing 50 of ' + matchTrials.length + ' trials</div>';
    }

    // Tafsir: Related Signs â€” grouped by type, colored pills, clickable zoom
    if (_tafsirLinks.length > 0) {
      var relLinks = _tafsirLinks.filter(function(l) { return l.sourceId === node.id || l.targetId === node.id; });
      if (relLinks.length > 0) {
        html += '<div style="margin-top:12px;padding-top:8px;border-top:1px solid var(--border)">';
        html += '<div style="font-weight:600;font-size:0.82rem;margin-bottom:4px">Related Signs (Tafsir)</div>';
        var typeColors = { drug: '#7c3aed', outcome: '#b45309', mechanism: '#0d9488' };
        var typeBgColors = { drug: '#a78bfa22', outcome: '#fbbf2422', mechanism: '#2dd4bf22' };
        var typeLabels = { drug: 'Drug Siblings', outcome: 'Outcome Bridges', mechanism: 'Mechanism Overlap' };
        var grouped = {};
        for (var ri = 0; ri < relLinks.length; ri++) {
          var rl = relLinks[ri];
          if (!grouped[rl.linkType]) grouped[rl.linkType] = [];
          grouped[rl.linkType].push(rl);
        }
        var typeOrder = ['drug', 'outcome', 'mechanism'];
        for (var ti = 0; ti < typeOrder.length; ti++) {
          var lt = typeOrder[ti];
          if (!grouped[lt] || grouped[lt].length === 0) continue;
          html += '<div style="margin-top:4px;font-size:0.75rem;color:var(--text-muted)">' + escapeHtml(typeLabels[lt]) + ':</div>';
          for (var gi = 0; gi < grouped[lt].length; gi++) {
            var gl = grouped[lt][gi];
            var sibId = gl.sourceId === node.id ? gl.targetId : gl.sourceId;
            var parts = sibId.split(':');
            var bgColor = typeColors[lt];
            html += '<span tabindex="0" role="button" onclick="zoomToAyatNode(\'' + escapeHtml(sibId) + '\')" onkeydown="if(event.key===\'Enter\'||event.key===\' \'){event.preventDefault();zoomToAyatNode(\'' + escapeHtml(sibId) + '\')}" style="display:inline-block;margin:2px 6px 2px 0;padding:2px 8px;background:' + (typeBgColors[lt] || bgColor + '22') + ';border:1px solid ' + bgColor + ';color:' + bgColor + ';border-radius:12px;font-size:0.75rem;cursor:pointer" title="' + escapeHtml(gl.label || '') + '">';
            html += escapeHtml(parts[1] || sibId) + ' <span style="opacity:0.7">(' + escapeHtml(parts[0] || '') + ')</span>';
            html += '</span>';
          }
        }
        html += '</div>';
      }
    }

    showDrillDownPanel(
      escapeHtml(node.label) + ' \u2014 ' + matchTrials.length + ' trials in ' + escapeHtml(node.subcatLabel),
      html
    );
  }

  // Drill-down for network edge: show shared interventions between two subcategories
  function drillDownNetworkEdge(nodeAIdx, nodeBIdx) {
    var a = networkNodes[nodeAIdx];
    var b = networkNodes[nodeBIdx];
    if (!a || !b || !universeTrialsCache) return;

    // Collect interventions per subcategory
    var ivsA = {}, ivsB = {};
    for (var i = 0; i < universeTrialsCache.length; i++) {
      var t = universeTrialsCache[i];
      var ivs = getTrialInterventionNames(t, { excludeComparators: true, maxItems: 6 });
      for (var j = 0; j < ivs.length; j++) {
        var name = ivs[j].toLowerCase().slice(0, 40);
        if (!name) continue;
        if (t.subcategory === a.id) { ivsA[name] = (ivsA[name] || 0) + 1; }
        if (t.subcategory === b.id) { ivsB[name] = (ivsB[name] || 0) + 1; }
      }
    }
    // Find shared
    var shared = [];
    for (var iv in ivsA) {
      if (ivsB[iv]) {
        shared.push({ name: iv, countA: ivsA[iv], countB: ivsB[iv], total: ivsA[iv] + ivsB[iv] });
      }
    }
    shared.sort(function(x, y) { return y.total - x.total; });

    var html = '<div style="margin-bottom:8px;font-size:0.85rem">';
    html += '<span style="color:' + a.color + ';font-weight:600">' + escapeHtml(a.label) + '</span>';
    html += ' (' + a.totalRCTs + ' RCTs) \u2194 ';
    html += '<span style="color:' + b.color + ';font-weight:600">' + escapeHtml(b.label) + '</span>';
    html += ' (' + b.totalRCTs + ' RCTs)';
    html += ' | <strong>' + shared.length + ' shared interventions</strong>';
    html += '</div>';

    if (shared.length === 0) {
      html += '<div style="color:var(--text-muted);padding:12px">No shared interventions found between these subcategories.</div>';
    } else {
      html += '<div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:0.82rem">';
      html += '<thead><tr style="background:var(--bg-alt,#f8fafc);text-align:left">';
      html += '<th style="padding:6px 8px;border-bottom:2px solid var(--border)">Intervention</th>';
      html += '<th style="padding:6px 8px;border-bottom:2px solid var(--border);text-align:right">' + escapeHtml(a.label) + ' trials</th>';
      html += '<th style="padding:6px 8px;border-bottom:2px solid var(--border);text-align:right">' + escapeHtml(b.label) + ' trials</th>';
      html += '<th style="padding:6px 8px;border-bottom:2px solid var(--border);text-align:right">Total</th>';
      html += '</tr></thead><tbody>';
      for (var s = 0; s < Math.min(shared.length, 30); s++) {
        var sh = shared[s];
        var rowBg = s % 2 === 0 ? '' : 'background:var(--bg-alt,#f8fafc);';
        html += '<tr style="' + rowBg + '">';
        html += '<td style="padding:5px 8px;border-bottom:1px solid var(--border)">' + escapeHtml(sh.name) + '</td>';
        html += '<td style="padding:5px 8px;border-bottom:1px solid var(--border);text-align:right">' + sh.countA + '</td>';
        html += '<td style="padding:5px 8px;border-bottom:1px solid var(--border);text-align:right">' + sh.countB + '</td>';
        html += '<td style="padding:5px 8px;border-bottom:1px solid var(--border);text-align:right;font-weight:600">' + sh.total + '</td>';
        html += '</tr>';
      }
      html += '</tbody></table></div>';
    }

    showDrillDownPanel(
      escapeHtml(a.label) + ' \u2194 ' + escapeHtml(b.label) + ' \u2014 Shared Interventions',
      html
    );
  }

  // Drill-down for network node: shows all trials + guideline context + gap analysis
  function drillDownNetworkNode(nodeIdx) {
    var n = networkNodes[nodeIdx];
    if (!n || !universeTrialsCache) return;

    var trials = universeTrialsCache.filter(function(t) { return t.subcategory === n.id; });

    var html = '<div style="display:flex;gap:16px;flex-wrap:wrap;margin-bottom:12px">';
    // Stats card
    html += '<div style="flex:1;min-width:180px">';
    html += '<div style="font-size:0.8rem;color:var(--text-muted)">Total RCTs</div><div style="font-size:1.3rem;font-weight:700">' + n.totalRCTs + '</div>';
    html += '<div style="font-size:0.8rem;color:var(--text-muted);margin-top:6px">Recent (3yr)</div><div style="font-weight:600">' + n.recentRCTs + '</div>';
    html += '<div style="font-size:0.8rem;color:var(--text-muted);margin-top:6px">Meta-analyses (5yr)</div><div>' + n.maCount + '</div>';
    html += '<div style="font-size:0.8rem;color:var(--text-muted);margin-top:6px">Gap Score</div>';
    html += '<div style="font-weight:600;color:' + (n.opportunity === 'HIGH' ? '#ef4444' : n.opportunity === 'MODERATE' ? '#f59e0b' : '#10b981') + '">' + n.gapScore.toFixed(1) + ' (' + n.opportunity + ')</div>';
    html += '</div>';

    // Top interventions
    html += '<div style="flex:1;min-width:180px">';
    html += '<div style="font-size:0.8rem;color:var(--text-muted)">Top Interventions</div>';
    var topIvs = (n.topInterventions || []).slice(0, 8);
    for (var ti = 0; ti < topIvs.length; ti++) {
      html += '<div style="font-size:0.82rem">' + (ti + 1) + '. ' + escapeHtml(topIvs[ti].name || topIvs[ti]) + (topIvs[ti].count ? ' (' + topIvs[ti].count + ')' : '') + '</div>';
    }
    html += '</div>';

    // Top outcomes
    html += '<div style="flex:1;min-width:180px">';
    html += '<div style="font-size:0.8rem;color:var(--text-muted)">Top Outcomes</div>';
    var topOcs = (n.topOutcomes || []).slice(0, 8);
    for (var to = 0; to < topOcs.length; to++) {
      html += '<div style="font-size:0.82rem">' + (to + 1) + '. ' + escapeHtml(topOcs[to].name || topOcs[to]) + (topOcs[to].count ? ' (' + topOcs[to].count + ')' : '') + '</div>';
    }
    html += '</div>';

    // Guideline context
    var gl = CV_GUIDELINES[n.id];
    if (gl && gl.keyDrugs.length > 0) {
      html += '<div style="flex:1;min-width:200px;padding:8px;background:rgba(99,102,241,0.06);border-radius:6px">';
      html += '<div style="font-size:0.8rem;color:var(--text-muted);margin-bottom:4px">Guidelines: ' + escapeHtml(gl.guidelines.join(', ')) + '</div>';
      for (var g = 0; g < gl.keyDrugs.length; g++) {
        var drug = gl.keyDrugs[g];
        var recCol = REC_COLORS[drug.rec] || '#888';
        html += '<div style="font-size:0.8rem;margin-bottom:2px"><span style="color:' + recCol + ';font-weight:700">' + escapeHtml(REC_SYMBOLS[drug.rec] || '') + ' ' + escapeHtml(drug.cls) + '</span>';
        html += ' <span style="opacity:0.7">Class ' + escapeHtml(drug.rec) + '/LoE ' + escapeHtml(drug.loe) + '</span>';
        if (drug.nnt) html += ' NNT=' + drug.nnt;
        html += '</div>';
      }
      html += '</div>';
    }
    html += '</div>';

    // Connected subcategories
    var connections = networkEdges.filter(function(e) { return e.source === nodeIdx || e.target === nodeIdx; });
    if (connections.length > 0) {
      html += '<div style="margin-top:8px;font-size:0.85rem"><strong>Connected subcategories</strong> (shared interventions) \u2014 click to explore</div>';
      html += '<div style="display:flex;flex-wrap:wrap;gap:6px;margin-top:4px">';
      for (var c = 0; c < connections.length; c++) {
        var edge = connections[c];
        var otherIdx = edge.source === nodeIdx ? edge.target : edge.source;
        var other = networkNodes[otherIdx];
        if (!other) continue;
        html += '<button onclick="drillDownNetworkEdge(' + nodeIdx + ',' + otherIdx + ')" style="padding:4px 10px;border:1px solid ' + other.color + ';border-radius:4px;background:none;color:var(--text);cursor:pointer;font-size:0.8rem">';
        html += '<span style="color:' + other.color + '">\u25CF</span> ' + escapeHtml(other.label) + ' (' + edge.weight + ' shared)';
        html += '</button>';
      }
      html += '</div>';
    }

    // Trial list
    html += '<div style="margin-top:12px"><strong>Trials (' + trials.length + ')</strong></div>';
    html += '<div style="overflow-x:auto;margin-top:6px"><table style="width:100%;border-collapse:collapse;font-size:0.82rem">';
    html += '<thead><tr style="background:var(--bg-alt,#f8fafc);text-align:left">';
    html += '<th style="padding:6px 8px;border-bottom:2px solid var(--border)">NCT ID</th>';
    html += '<th style="padding:6px 8px;border-bottom:2px solid var(--border)">Title</th>';
    html += '<th style="padding:6px 8px;border-bottom:2px solid var(--border)">Interventions</th>';
    html += '<th style="padding:6px 8px;border-bottom:2px solid var(--border);text-align:right">N</th>';
    html += '<th style="padding:6px 8px;border-bottom:2px solid var(--border)">Phase</th>';
    html += '<th style="padding:6px 8px;border-bottom:2px solid var(--border)">Year</th>';
    html += '</tr></thead><tbody>';
    var show = trials.slice(0, 50);
    for (var i = 0; i < show.length; i++) {
      var t = show[i];
      var nctLink = t.nctId ? '<a href="https://clinicaltrials.gov/study/' + escapeHtml(t.nctId) + '" target="_blank" rel="noopener" style="color:var(--primary);font-family:monospace;font-size:0.78rem">' + escapeHtml(t.nctId) + '</a>' : 'N/A';
      var titleShort = (t.title || '').length > 60 ? t.title.substring(0, 57) + '...' : (t.title || '');
      var ivs = getTrialInterventionNames(t, {
        excludeComparators: true,
        maxItems: 6,
        fallbackLabel: 'Intervention not specified'
      }).join(', ');
      if (ivs.length > 40) ivs = ivs.substring(0, 37) + '...';
      var rowBg = i % 2 === 0 ? '' : 'background:var(--bg-alt,#f8fafc);';
      html += '<tr style="' + rowBg + '"><td style="padding:5px 8px;border-bottom:1px solid var(--border);white-space:nowrap">' + nctLink + '</td>';
      html += '<td style="padding:5px 8px;border-bottom:1px solid var(--border)" title="' + escapeHtml(t.title || '') + '">' + escapeHtml(titleShort) + '</td>';
      html += '<td style="padding:5px 8px;border-bottom:1px solid var(--border);font-size:0.78rem">' + escapeHtml(ivs) + '</td>';
      html += '<td style="padding:5px 8px;border-bottom:1px solid var(--border);text-align:right">' + (t.enrollment || '?') + '</td>';
      html += '<td style="padding:5px 8px;border-bottom:1px solid var(--border)">' + (t.phase || '?') + '</td>';
      html += '<td style="padding:5px 8px;border-bottom:1px solid var(--border)">' + (t.startYear || '?') + '</td></tr>';
    }
    html += '</tbody></table></div>';
    if (trials.length > 50) {
      html += '<div style="margin-top:6px;font-size:0.8rem;color:var(--text-muted)">Showing 50 of ' + trials.length + '</div>';
    }

    showDrillDownPanel(
      escapeHtml(n.label) + ' \u2014 ' + n.totalRCTs + ' RCTs, Gap ' + n.gapScore.toFixed(1),
      html
    );
  }

  function pickSuggestedInterventionForSubcategory(subcatId) {
    const node = networkNodes.find(n => n.id === subcatId);
    if (!node) return '';
    const candidates = (node.topInterventions || [])
      .map(iv => cleanInterventionLabel(typeof iv === 'string' ? iv : iv?.name))
      .filter(Boolean);
    return candidates.find(iv => !isComparatorIntervention(iv, '')) || '';
  }

  function startReviewFromUniverse(interventionLabel, subcatId) {
    const cat = getSubcategory(subcatId);
    let pickedIntervention = cleanInterventionLabel(interventionLabel);
    if (!pickedIntervention || isComparatorIntervention(pickedIntervention, '') || /^intervention not specified$/i.test(pickedIntervention)) {
      pickedIntervention = pickSuggestedInterventionForSubcategory(subcatId) || 'intervention of interest';
    }
    const project = projects.find(p => p.id === currentProjectId);
    if (project) {
      project.pico = {
        P: cat.label.toLowerCase().includes('hypertension') ? 'adults with hypertension' :
           'adults with ' + cat.label.toLowerCase(),
        I: pickedIntervention,
        C: 'placebo or standard care',
        O: cat.id === 'hf' ? 'CV death or HF hospitalization' :
           cat.id === 'acs' ? 'MACE (CV death, MI, stroke)' :
           cat.id === 'af' ? 'stroke or systemic embolism' :
           'cardiovascular outcomes'
      };
      idbPut('projects', project);
    }
    switchPhase('protocol');
    loadPICO();
    showToast('PICO populated from ' + cat.label + ' universe', 'success');
  }

  function sortUniverse(mode, btn) {
    document.querySelectorAll('#universeControls .filter-btn').forEach(b => b.classList.remove('active'));
    if (btn) btn.classList.add('active');
    if (!currentGridSubcat) {
      if (mode === 'gap' && networkNodes.length > 0) {
        const sorted = [...networkNodes].sort((a, b) => b.gapScore - a.gapScore);
        if (sorted[0]) expandSubcategory(networkNodes.indexOf(sorted[0]));
      }
      return;
    }
    renderUniverseGrid(currentGridTrials, currentGridSubcat, mode);
  }

  // ============================================================
  // UNIVERSE VIEW SYSTEM â€” 6 Interactive Visualization Views
  // ============================================================
  let currentUniverseView = 'network';
  let universeTrialsCache = []; // all loaded trials for views

  function switchUniverseView(viewName) {
    currentUniverseView = viewName;
    // Update tabs
    document.querySelectorAll('.view-tab').forEach(tab => {
      const isActive = tab.dataset.view === viewName;
      tab.classList.toggle('active', isActive);
      tab.setAttribute('aria-selected', isActive);
    });
    // Show/hide view containers
    document.querySelectorAll('.universe-view').forEach(el => el.classList.remove('active'));
    const viewMap = {
      alburhan: 'alBurhanCanvas',
      ayat: 'ayatCanvas', network: 'networkSvg', treemap: 'treemapCanvas', timeline: 'timelineCanvas',
      matrix: 'matrixCanvas', gapscatter: 'gapScatterCanvas', pipeline: 'pipelineSvg'
    };
    const target = document.getElementById(viewMap[viewName]);
    if (target) target.classList.add('active');
    // Al-Burhan has its own data pipeline, does not require universeTrialsCache
    if (viewName === 'alburhan') {
      renderAlBurhanUniverse();
      safeSetStorage('msa-universe-view', viewName);
      return;
    }
    // Render the selected view
    const trials = universeTrialsCache;
    if (trials.length === 0) return;
    switch (viewName) {
      case 'ayat': renderAyatUniverse(trials); break;
      case 'network': /* already rendered */ break;
      case 'treemap': renderTreemapView(trials); break;
      case 'timeline': renderTimelineView(trials); break;
      case 'matrix': renderBayanMatrix(trials); break;
      case 'gapscatter': renderGapScatterView(trials); break;
      case 'pipeline': renderPipelineView(trials); break;
    }
    safeSetStorage('msa-universe-view', viewName);
  }

  function showUniverseViewTabs() {
    const tabs = document.getElementById('universeViewTabs');
    if (tabs) tabs.style.display = 'flex';
    const hint = document.getElementById('universeOnboardHint');
    if (hint) hint.style.display = 'block';
  }

  // ============================================================
  // AYAT UNIVERSE â€” Information-Dense Evidence Landscape (Canvas)
  // ============================================================
  // Quranic design principles:
  //   Ayat (signs): every node, edge, void encodes data
  //   Ghayb (unseen): empty space reveals evidence gaps
  //   Tanzil (revelation): semantic zoom unveils progressive detail
  //   Ijaz (conciseness): maximum meaning per pixel
  //   Silat (connections): edges carry shared interventions/outcomes

  // --- Ayat Quadtree for O(log4 N) spatial queries ---
  class AyatQuadtree {
    constructor(x, y, w, h, depth) {
      this.x = x; this.y = y; this.w = w; this.h = h;
      this.depth = depth ?? 0; this.items = []; this.children = null;
    }
    insert(item) { // item = { x, y, r, data }
      if (item.x < this.x || item.x > this.x + this.w || item.y < this.y || item.y > this.y + this.h) return;
      if (this.items.length < 4 || this.depth >= 8) { this.items.push(item); return; }
      if (!this.children) this._subdivide();
      for (const c of this.children) c.insert(item);
    }
    _subdivide() {
      const hw = this.w / 2, hh = this.h / 2, d = this.depth + 1;
      this.children = [
        new AyatQuadtree(this.x, this.y, hw, hh, d),
        new AyatQuadtree(this.x + hw, this.y, hw, hh, d),
        new AyatQuadtree(this.x, this.y + hh, hw, hh, d),
        new AyatQuadtree(this.x + hw, this.y + hh, hw, hh, d)
      ];
      for (const it of this.items) for (const c of this.children) c.insert(it);
      this.items = [];
    }
    query(px, py, radius) {
      const results = [];
      this._queryR(px, py, radius, results);
      return results;
    }
    _queryR(px, py, radius, out) {
      if (px + radius < this.x || px - radius > this.x + this.w ||
          py + radius < this.y || py - radius > this.y + this.h) return;
      for (const it of this.items) {
        const dx = it.x - px, dy = it.y - py;
        if (dx * dx + dy * dy <= (it.r + radius) * (it.r + radius)) out.push(it);
      }
      if (this.children) for (const c of this.children) c._queryR(px, py, radius, out);
    }
  }

  // --- Build Ayat clusters: group trials â†’ subcategory â†’ intervention groups ---
  function buildAyatClusters(trials) {
    const subcatGroups = {};
    for (const t of trials) {
      const sc = t.subcategory || 'general';
      if (!subcatGroups[sc]) subcatGroups[sc] = [];
      subcatGroups[sc].push(t);
    }

    const nodes = [];
    for (const [scId, scTrials] of Object.entries(subcatGroups)) {
      const cat = getSubcategory(scId);
      // Group by top interventions within this subcategory
      const ivGroups = {};
      for (const t of scTrials) {
        const ivNames = getTrialInterventionNames(t, {
          excludeComparators: true,
          maxItems: 3,
          fallbackLabel: 'Intervention not specified'
        }).map(n => n.slice(0, 30)).filter(n => n.length > 2);
        const key = ivNames.length > 0 ? ivNames[0] : 'Other';
        if (!ivGroups[key]) ivGroups[key] = [];
        ivGroups[key].push(t);
      }
      // Keep top 8 intervention groups per subcategory, merge rest into "Other"
      const sorted = Object.entries(ivGroups).sort((a, b) => b[1].length - a[1].length);
      const top8 = sorted.slice(0, 8);
      const rest = sorted.slice(8);
      if (rest.length > 0) {
        const otherTrials = rest.flatMap(([, ts]) => ts);
        const existingOther = top8.find(([k]) => k === 'Other');
        if (existingOther) existingOther[1].push(...otherTrials);
        else top8.push(['Other', otherTrials]);
      }

      for (const [ivName, ivTrials] of top8) {
        if (ivTrials.length < 1) continue;
        const enrollment = ivTrials.reduce((a, t) => a + (t.enrollment ?? 0), 0);
        const phases = { 1: 0, 2: 0, 3: 0, 4: 0 };
        const curYear = new Date().getFullYear();
        let recentCount = 0;
        const yearCounts = {};
        const outcomes = {};
        for (const t of ivTrials) {
          const ph = parseInt(String(t.phase || '').replace(/[^0-9]/g, '')) || 0;
          if (ph >= 1 && ph <= 4) phases[ph]++;
          if ((t.startYear ?? 0) >= curYear - 3) recentCount++;
          const yr = t.startYear ?? 0;
          if (yr > 2000) yearCounts[yr] = (yearCounts[yr] ?? 0) + 1;
          for (const o of (t.primaryOutcomes || [])) {
            const norm = normalizeOutcome(o);
            if (norm) outcomes[norm] = (outcomes[norm] ?? 0) + 1;
          }
        }
        // Sparkline: last 10 years
        const sparkline = [];
        for (let y = curYear - 9; y <= curYear; y++) sparkline.push(yearCounts[y] ?? 0);

        nodes.push({
          id: scId + ':' + ivName,
          subcatId: scId, subcatLabel: cat.label,
          label: ivName, color: cat.color,
          x: 0, y: 0, r: 0, // set by layout
          trialCount: ivTrials.length,
          enrollment,
          phases,
          recentCount,
          sparkline,
          topOutcomes: Object.entries(outcomes).sort((a, b) => b[1] - a[1]).slice(0, 3).map(([k]) => k),
          gapScore: recentCount * Math.log2(ivTrials.length + 1),
          isHot: recentCount > 3,
          aactCount: ivTrials.filter(t => (t.source || '') === 'aact').length,
          aactPct: ivTrials.length > 0 ? ivTrials.filter(t => (t.source || '') === 'aact').length / ivTrials.length : 0
        });
      }
    }
    return nodes;
  }

  // --- Build edges: shared outcomes or same drug class ---
  function buildAyatEdges(clusters) {
    const edges = [];
    for (let i = 0; i < clusters.length; i++) {
      for (let j = i + 1; j < clusters.length; j++) {
        const a = clusters[i], b = clusters[j];
        // Shared outcomes
        const sharedOutcomes = a.topOutcomes.filter(o => b.topOutcomes.includes(o));
        // Same subcategory bonus
        const sameSubcat = a.subcatId === b.subcatId;
        const weight = sharedOutcomes.length + (sameSubcat ? 0.5 : 0);
        if (weight > 0) {
          edges.push({
            source: i, target: j,
            weight: Math.min(weight, 5),
            sharedOutcomes,
            type: sameSubcat ? 'intra' : 'inter'
          });
        }
      }
    }
    return edges;
  }

  // --- Compute evidence voids: subcategory Ã— outcome gaps ---
  function computeEvidenceVoids(clusters) {
    const allOutcomes = new Set();
    const subcatOutcomes = {};
    for (const node of clusters) {
      if (!subcatOutcomes[node.subcatId]) subcatOutcomes[node.subcatId] = new Set();
      for (const o of node.topOutcomes) {
        allOutcomes.add(o);
        subcatOutcomes[node.subcatId].add(o);
      }
    }
    const voids = [];
    for (const [scId, scOuts] of Object.entries(subcatOutcomes)) {
      for (const outcome of allOutcomes) {
        if (!scOuts.has(outcome)) {
          voids.push({ subcatId: scId, outcome, label: getSubcategory(scId).label + ' Ã— ' + outcome });
        }
      }
    }
    return voids;
  }

  // --- Force-directed layout with subcategory gravity ---
  function layoutAyatNodes(nodes, edges, W, H) {
    if (nodes.length === 0) return;
    const rng = mulberry32(42);
    // Assign radii based on trial count
    const maxCount = Math.max(1, ...nodes.map(n => n.trialCount));
    for (const n of nodes) {
      n.r = 8 + Math.sqrt(n.trialCount / maxCount) * 28;
    }
    // Initial positions: subcategories arranged in a circle, nodes clustered near their subcategory
    const subcatIds = [...new Set(nodes.map(n => n.subcatId))];
    const subcatAngles = {};
    subcatIds.forEach((id, i) => {
      subcatAngles[id] = (2 * Math.PI * i) / subcatIds.length - Math.PI / 2;
    });
    const cx = W / 2, cy = H / 2, orbitR = Math.min(W, H) * 0.3;
    for (const n of nodes) {
      const angle = subcatAngles[n.subcatId] + (rng() - 0.5) * 0.6;
      const dist = orbitR * (0.6 + rng() * 0.4);
      n.x = cx + Math.cos(angle) * dist;
      n.y = cy + Math.sin(angle) * dist;
    }
    // Run force simulation (100 iterations)
    for (let iter = 0; iter < 100; iter++) {
      const alpha = 0.3 * (1 - iter / 100);
      // Repulsion between all nodes
      for (let i = 0; i < nodes.length; i++) {
        for (let j = i + 1; j < nodes.length; j++) {
          let dx = nodes[j].x - nodes[i].x, dy = nodes[j].y - nodes[i].y;
          const dist = Math.sqrt(dx * dx + dy * dy) || 1;
          const minDist = nodes[i].r + nodes[j].r + 8;
          if (dist < minDist * 3) {
            const force = alpha * 400 / (dist * dist);
            dx *= force; dy *= force;
            nodes[i].x -= dx; nodes[i].y -= dy;
            nodes[j].x += dx; nodes[j].y += dy;
          }
        }
      }
      // Edge attraction
      for (const e of edges) {
        const a = nodes[e.source], b = nodes[e.target];
        let dx = b.x - a.x, dy = b.y - a.y;
        const dist = Math.sqrt(dx * dx + dy * dy) || 1;
        const idealDist = (a.r + b.r) * 2.5;
        const force = alpha * (dist - idealDist) * 0.01;
        dx = (dx / dist) * force; dy = (dy / dist) * force;
        a.x += dx; a.y += dy; b.x -= dx; b.y -= dy;
      }
      // Subcategory gravity: pull nodes toward their subcategory center
      for (const n of nodes) {
        const angle = subcatAngles[n.subcatId];
        const gx = cx + Math.cos(angle) * orbitR;
        const gy = cy + Math.sin(angle) * orbitR;
        n.x += (gx - n.x) * alpha * 0.08;
        n.y += (gy - n.y) * alpha * 0.08;
      }
      // Center gravity
      for (const n of nodes) {
        n.x += (cx - n.x) * alpha * 0.01;
        n.y += (cy - n.y) * alpha * 0.01;
      }
      // Boundary constraint
      for (const n of nodes) {
        n.x = Math.max(n.r + 4, Math.min(W - n.r - 4, n.x));
        n.y = Math.max(n.r + 4, Math.min(H - n.r - 4, n.y));
      }
    }
  }

  // --- Render evidence density field (ghayb â€” the unseen) ---
  function renderGhayb(ctx, nodes, voids, W, H, lod) {
    if (lod < 1) return; // skip at lowest zoom
    // Compute density: areas far from any node are "voids"
    const gridSize = lod >= 2 ? 20 : 40;
    const cols = Math.ceil(W / gridSize), rows = Math.ceil(H / gridSize);
    for (let r = 0; r < rows; r++) {
      for (let c = 0; c < cols; c++) {
        const px = c * gridSize + gridSize / 2;
        const py = r * gridSize + gridSize / 2;
        // Compute distance to nearest node
        let minDist = Infinity;
        for (const n of nodes) {
          const dx = n.x - px, dy = n.y - py;
          const d = Math.sqrt(dx * dx + dy * dy) - n.r;
          if (d < minDist) minDist = d;
        }
        // Void intensity: farther from nodes = stronger void
        if (minDist > 60) {
          const intensity = Math.min(0.25, (minDist - 60) / 400);
          ctx.fillStyle = `rgba(239, 68, 68, ${intensity})`; // soft red void glow
          ctx.fillRect(c * gridSize, r * gridSize, gridSize, gridSize);
        }
      }
    }
    // At higher LOD: label the void regions
    if (lod >= 2 && voids.length > 0) {
      ctx.font = '9px system-ui';
      ctx.fillStyle = 'rgba(239, 68, 68, 0.4)';
      ctx.textAlign = 'center';
      // Find centroid of void regions (midpoint between relevant subcategory clusters)
      const subcatCentroids = {};
      for (const n of nodes) {
        if (!subcatCentroids[n.subcatId]) subcatCentroids[n.subcatId] = { sx: 0, sy: 0, count: 0 };
        subcatCentroids[n.subcatId].sx += n.x;
        subcatCentroids[n.subcatId].sy += n.y;
        subcatCentroids[n.subcatId].count++;
      }
      for (const sc in subcatCentroids) {
        const c = subcatCentroids[sc];
        c.cx = c.sx / c.count; c.cy = c.sy / c.count;
      }
      const shown = new Set();
      for (const v of voids.slice(0, 12)) {
        const sc = subcatCentroids[v.subcatId];
        if (!sc || shown.has(v.subcatId)) continue;
        shown.add(v.subcatId);
        // Place void label slightly outside the subcategory cluster
        const angle = Math.atan2(sc.cy - H / 2, sc.cx - W / 2);
        const vx = sc.cx + Math.cos(angle) * 70;
        const vy = sc.cy + Math.sin(angle) * 70;
        ctx.fillText('gap: ' + v.outcome, vx, vy);
      }
    }
  }

  // --- Render edges (silat â€” connections that carry meaning) ---
  function renderAyatEdges(ctx, edges, nodes, lod) {
    const outcomeColors = {
      'Mortality/Survival': '#ef4444', 'Composite endpoint': '#f97316',
      'Hospitalization': '#eab308', 'Blood pressure': '#3b82f6',
      'Ejection fraction': '#ec4899', 'Safety/Adverse events': '#64748b',
      'Quality of life': '#10b981'
    };
    for (const e of edges) {
      const a = nodes[e.source], b = nodes[e.target];
      const dx = b.x - a.x, dy = b.y - a.y;
      const dist = Math.sqrt(dx * dx + dy * dy) || 1;
      // Start/end at node borders
      const sx = a.x + (dx / dist) * a.r, sy = a.y + (dy / dist) * a.r;
      const ex = b.x - (dx / dist) * b.r, ey = b.y - (dy / dist) * b.r;

      ctx.beginPath();
      ctx.moveTo(sx, sy);
      // Curved edge for inter-subcategory connections
      if (e.type === 'inter') {
        const mx = (sx + ex) / 2, my = (sy + ey) / 2;
        const nx = -(ey - sy) * 0.15, ny = (ex - sx) * 0.15;
        ctx.quadraticCurveTo(mx + nx, my + ny, ex, ey);
      } else {
        ctx.lineTo(ex, ey);
      }

      // Edge color from primary shared outcome
      const primaryOutcome = e.sharedOutcomes[0] || '';
      const edgeColor = outcomeColors[primaryOutcome] ?? '#475569';
      ctx.strokeStyle = edgeColor + (e.type === 'intra' ? '40' : '70');
      ctx.lineWidth = 0.5 + e.weight * 0.8;
      ctx.stroke();

      // At LOD 2+: label on edge
      if (lod >= 2 && e.sharedOutcomes.length > 0 && dist > 80) {
        const lx = (sx + ex) / 2, ly = (sy + ey) / 2;
        ctx.font = '7px system-ui';
        ctx.fillStyle = edgeColor + 'aa';
        ctx.textAlign = 'center';
        ctx.fillText(e.sharedOutcomes[0], lx, ly - 3);
      }
    }
  }

  // --- Render multi-ring glyph (ayat â€” each node is a sign) ---
  function renderAyatGlyph(ctx, node, lod) {
    const { x, y, r, color, trialCount, enrollment, phases, recentCount, sparkline, topOutcomes, label, subcatLabel, isHot, gapScore, aactPct = 0 } = node;
    const tc = getThemeColors();

    // LOD 0: Simple colored dot
    if (lod === 0) {
      ctx.beginPath();
      ctx.arc(x, y, Math.max(3, r * 0.4), 0, Math.PI * 2);
      ctx.fillStyle = color + 'cc';
      ctx.fill();
      return;
    }

    // LOD 1: Sized circle with trial count
    if (lod === 1) {
      // Outer ring
      ctx.beginPath();
      ctx.arc(x, y, r, 0, Math.PI * 2);
      ctx.fillStyle = color + '33';
      ctx.fill();
      ctx.strokeStyle = color + '99';
      ctx.lineWidth = 1.5;
      ctx.stroke();
      // AACT ring at LOD 1
      if (aactPct > 0.5) {
        ctx.beginPath();
        ctx.arc(x, y, r + 2, 0, Math.PI * 2);
        ctx.strokeStyle = '#22d3ee';
        ctx.lineWidth = 1.5;
        ctx.stroke();
      }
      // Core: enrollment magnitude
      const coreR = Math.max(4, r * 0.5);
      ctx.beginPath();
      ctx.arc(x, y, coreR, 0, Math.PI * 2);
      ctx.fillStyle = color + '88';
      ctx.fill();
      // Label
      ctx.fillStyle = tc.text;
      ctx.font = 'bold ' + Math.max(8, r * 0.35) + 'px system-ui';
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillText(trialCount, x, y);
      return;
    }

    // LOD 2-3: Full multi-ring glyph

    // Opportunity glow (for high gap score nodes)
    if (gapScore > (window.GAP_THRESHOLD_MOD ?? 3)) {
      const gradient = ctx.createRadialGradient(x, y, r, x, y, r * 1.8);
      gradient.addColorStop(0, color + '30');
      gradient.addColorStop(1, color + '00');
      ctx.beginPath();
      ctx.arc(x, y, r * 1.8, 0, Math.PI * 2);
      ctx.fillStyle = gradient;
      ctx.fill();
    }

    // Ring 1 (outer): Phase distribution donut
    const totalPhases = phases[1] + phases[2] + phases[3] + phases[4];
    if (totalPhases > 0) {
      const phaseColors = { 1: '#60a5fa', 2: '#34d399', 3: '#fbbf24', 4: '#f87171' };
      let startAngle = -Math.PI / 2;
      for (let p = 1; p <= 4; p++) {
        if (phases[p] === 0) continue;
        const sweep = (phases[p] / totalPhases) * Math.PI * 2;
        ctx.beginPath();
        ctx.arc(x, y, r, startAngle, startAngle + sweep);
        ctx.arc(x, y, r * 0.72, startAngle + sweep, startAngle, true);
        ctx.closePath();
        ctx.fillStyle = phaseColors[p] + 'cc';
        ctx.fill();
        startAngle += sweep;
      }
    } else {
      ctx.beginPath();
      ctx.arc(x, y, r, 0, Math.PI * 2);
      ctx.strokeStyle = color + '66';
      ctx.lineWidth = r * 0.28;
      ctx.stroke();
    }

    // AACT source ring: thin cyan ring around nodes >50% AACT-sourced
    if (aactPct > 0.5) {
      ctx.beginPath();
      ctx.arc(x, y, r + 2.5, 0, Math.PI * 2);
      ctx.strokeStyle = '#22d3ee';
      ctx.lineWidth = 2;
      ctx.stroke();
    }

    // Ring 2 (inner): Enrollment magnitude
    const coreR = r * 0.65;
    ctx.beginPath();
    ctx.arc(x, y, coreR, 0, Math.PI * 2);
    ctx.fillStyle = color + '44';
    ctx.fill();
    ctx.strokeStyle = color + 'aa';
    ctx.lineWidth = 1;
    ctx.stroke();

    // Core: trial count number
    ctx.fillStyle = tc.text;
    ctx.font = 'bold ' + Math.max(9, r * 0.4) + 'px system-ui';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillText(trialCount, x, y - (lod >= 3 ? 2 : 0));

    // Activity indicator (sparkline arc) at LOD 2+
    if (sparkline.length > 0) {
      const maxSpk = Math.max(1, ...sparkline);
      const arcR = r * 0.85;
      const arcStart = Math.PI * 0.75;
      const arcSweep = Math.PI * 0.5;
      ctx.lineWidth = 1.5;
      for (let i = 0; i < sparkline.length - 1; i++) {
        const t1 = i / (sparkline.length - 1);
        const t2 = (i + 1) / (sparkline.length - 1);
        const a1 = arcStart + t1 * arcSweep;
        const a2 = arcStart + t2 * arcSweep;
        const v1 = sparkline[i] / maxSpk;
        const v2 = sparkline[i + 1] / maxSpk;
        const r1 = arcR + v1 * 6, r2 = arcR + v2 * 6;
        ctx.beginPath();
        ctx.moveTo(x + Math.cos(a1) * r1, y + Math.sin(a1) * r1);
        ctx.lineTo(x + Math.cos(a2) * r2, y + Math.sin(a2) * r2);
        ctx.strokeStyle = recentCount > 3 ? '#fbbf24' : tc.textMuted;
        ctx.stroke();
      }
    }

    // Hot badge (recent activity > 3)
    if (isHot) {
      ctx.beginPath();
      ctx.arc(x + r * 0.7, y - r * 0.7, 5, 0, Math.PI * 2);
      ctx.fillStyle = '#ef4444';
      ctx.fill();
      ctx.fillStyle = tc.surface;
      ctx.font = 'bold 6px system-ui';
      ctx.fillText('!', x + r * 0.7, y - r * 0.7 + 1);
    }

    // LOD 3: Full labels + outcomes
    if (lod >= 3) {
      // Intervention label below count
      ctx.fillStyle = tc.text;
      ctx.font = Math.max(7, r * 0.22) + 'px system-ui';
      ctx.textAlign = 'center';
      ctx.fillText(label.length > 20 ? label.slice(0, 18) + '..' : label, x, y + r * 0.25);

      // Subcategory label above
      ctx.fillStyle = color + 'bb';
      ctx.font = 'bold ' + Math.max(6, r * 0.18) + 'px system-ui';
      ctx.fillText(subcatLabel, x, y - r - 6);

      // Enrollment below node
      const enrText = enrollment > 10000 ? Math.round(enrollment / 1000) + 'K' :
                      enrollment > 0 ? enrollment.toLocaleString() : '?';
      ctx.fillStyle = tc.textMuted;
      ctx.font = '7px system-ui';
      ctx.fillText('n=' + enrText, x, y + r + 10);

      // Top outcomes below enrollment
      if (topOutcomes.length > 0) {
        ctx.fillStyle = tc.textMuted;
        ctx.font = '6px system-ui';
        ctx.fillText(topOutcomes.slice(0, 2).join(', '), x, y + r + 19);
      }

      // Phase legend at bottom
      ctx.font = '6px system-ui';
      const phLabels = ['I', 'II', 'III', 'IV'];
      const phColors = ['#60a5fa', '#34d399', '#fbbf24', '#f87171'];
      let lx = x - 14;
      for (let p = 0; p < 4; p++) {
        if (phases[p + 1] > 0) {
          ctx.fillStyle = phColors[p];
          ctx.fillRect(lx, y + r + 23, 4, 4);
          ctx.fillStyle = tc.textMuted;
          ctx.fillText(phLabels[p], lx + 5, y + r + 27);
          lx += 12;
        }
      }
    }

    // Hukm verdict badge (LOD 2+): small colored icon in bottom-left of node
    if (_kitabLayers.verdicts && lod >= 2) {
      const hukm = _hukmVerdicts.get(node.id);
      if (hukm) {
        const icon = HUKM_ICONS[hukm.verdict] || HUKM_ICONS.INCONCLUSIVE;
        const bx = x - r * 0.65, by = y + r * 0.55;
        ctx.beginPath();
        ctx.arc(bx, by, 7, 0, Math.PI * 2);
        ctx.fillStyle = icon.color;
        ctx.fill();
        ctx.fillStyle = '#fff';
        ctx.font = 'bold 9px system-ui';
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillText(icon.symbol, bx, by);
      }
    }
  }

